#include <stdio.h>
#include <assert.h>

int min3(int a, int b, int c) { return a < b ? (a < c ? a : c) : (b < c ? b : c); }

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    assert(1 <= T && T <= 100);
    while (T--) {
        int N; scanf("%d", &N);
        assert(1 <= N && N <= 100);
        int mat[100][100];
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                scanf("%d", &mat[i][j]);
                assert(mat[i][j] == 0 || mat[i][j] == 1);
            }
        }
        int dp[100][100];
        int maxSide = 0;
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                if (i == 0 || j == 0) dp[i][j] = mat[i][j];
                else if (mat[i][j] == 1) dp[i][j] = 1 + min3(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
                else dp[i][j] = 0;
                if (dp[i][j] > maxSide) maxSide = dp[i][j];
            }
        }
        printf("%d\n", maxSide * maxSide);
    }
    return 0;
}

