import java.io.*;
import java.util.*;

public class Main {
    private static int min3(int a, int b, int c) { return Math.min(a, Math.min(b, c)); }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        if (T < 1 || T > 100) throw new AssertionError();
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int N = Integer.parseInt(br.readLine().trim());
            if (N < 1 || N > 100) throw new AssertionError();
            int[][] mat = new int[N][N];
            for (int i = 0; i < N; ++i) {
                st = new StringTokenizer(br.readLine());
                for (int j = 0; j < N; ++j) {
                    mat[i][j] = Integer.parseInt(st.nextToken());
                    if (mat[i][j] != 0 && mat[i][j] != 1) throw new AssertionError();
                }
            }
            int[][] dp = new int[N][N];
            int maxSide = 0;
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) {
                    if (i == 0 || j == 0) dp[i][j] = mat[i][j];
                    else if (mat[i][j] == 1) dp[i][j] = 1 + min3(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
                    else dp[i][j] = 0;
                    if (dp[i][j] > maxSide) maxSide = dp[i][j];
                }
            }
            out.append(maxSide * maxSide).append('\n');
        }
        System.out.print(out.toString());
    }
}

