import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    assert 1 <= T <= 100
    outputs = []
    for _ in range(T):
        N = int(next(it))
        assert 1 <= N <= 100
        mat = [[int(next(it)) for _ in range(N)] for _ in range(N)]
        dp = [[0]*N for _ in range(N)]
        max_side = 0
        for i in range(N):
            for j in range(N):
                if i == 0 or j == 0:
                    dp[i][j] = mat[i][j]
                elif mat[i][j] == 1:
                    dp[i][j] = 1 + min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1])
                else:
                    dp[i][j] = 0
                if dp[i][j] > max_side:
                    max_side = dp[i][j]
        outputs.append(str(max_side * max_side))
    sys.stdout.write('\n'.join(outputs))

if __name__ == "__main__":
    solve()

