const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(data[idx++]);
if (T < 1 || T > 100) throw new Error('Invalid T');
let results = [];
for (let tc = 0; tc < T; ++tc) {
  const N = Number(data[idx++]);
  if (N < 1 || N > 100) throw new Error('Invalid N');
  const mat = Array.from({ length: N }, () => Array(N).fill(0));
  for (let i = 0; i < N; ++i) {
    for (let j = 0; j < N; ++j) {
      const val = Number(data[idx++]);
      if (val !== 0 && val !== 1) throw new Error('Invalid cell');
      mat[i][j] = val;
    }
  }
  const dp = Array.from({ length: N }, () => Array(N).fill(0));
  let maxSide = 0;
  for (let i = 0; i < N; ++i) {
    for (let j = 0; j < N; ++j) {
      if (i === 0 || j === 0) dp[i][j] = mat[i][j];
      else if (mat[i][j] === 1) dp[i][j] = 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
      else dp[i][j] = 0;
      if (dp[i][j] > maxSide) maxSide = dp[i][j];
    }
  }
  results.push(String(maxSide * maxSide));
}
